import sqlite3

def advanced_search(database_path, conditions):
    conn = sqlite3.connect(database_path)
    cursor = conn.cursor()
    
    query = "SELECT * FROM users WHERE "
    params = []
    
    for i, condition in enumerate(conditions):
        field = condition['field']
        op = condition['op']
        value = condition['value']
        
        if i > 0:
            query += " AND "
        
        if op == 'LIKE':
            query += f"{field} LIKE ?"
            params.append(f"%{value}%")
        else:
            query += f"{field} {op} ?"
            params.append(value)
    
    cursor.execute(query, params)
    results = cursor.fetchall()
    
    conn.close()
    return results

# Example usage
conditions = [
    {'field': 'age', 'op': '>', 'value': 18},
    {'field': 'city', 'op': '=', 'value': 'NYC'}
]
results = advanced_search('database.db', conditions)
print(results)